# Music-themed bias set
MUSIC = set("ADELE ALBUM ARENA BANJO BASSO BEATS BEBOP BLUES BONGO BOWIE BRASS BRAVO BUGLE CANON CAPOS CAROL CELLO CHANT CHIME CHOIR CHORD CLEFS CLINK COMBO CONGA COVER CRADLE DANCE DEMOS DIRGE DISCO DITTY DIVAS DJINN DRAKE DRAMA DRESS DREAM DRIVE DROPS DRUMS DUETS DUMBO DYLAN EAGLE EDDIE ELITE ELOPE ELTON ELVIS EMCEE EMOTE ENJOY ENTER EQUAL EQUIP ETHEL EVENT EVITA EXTRA FLUTE FORTE GENRE GUEST HARPS HEAVY HELLO HONOR HOUSE HYMNS IDOLS JAZZY KAZOO LATIN LAYLA LEMON LILAC LOVER LOWER LYRES LYRIC MAJOR METAL METER METRO MEZZO MINOR MODEM MOVIE MUSED MUSES MUSIC NOISE NOTES OASIS OBOES OPERA ORGAN PIANO PLAYS PRIDE PRIME PRIZE PSALM PUNKS QUEEN RADIO RAPS REGGAE REMIX RHYME RIFFS RIOTS RIVER ROCKS ROUND SAMBA SCALE SCORE SINGS SOLOS SONGS SONIC SOULS STARS STING STYLE SUITE SUPER SWING TANGO TEMPO TENOR THIRD TIMER TONAL TONES TUBAS TUNES VIDEO VIOLA VOCAL VOICE WALTZ".split())

WORDS_5 = sorted(w for w in WORDS if isinstance(w, str) and len(w) == 5 and w.isalpha())
# Trim awkward plurals of proper nouns / abbreviations / obscure
BANNED = {'IOWAS', 'OHIOS', 'OASYS', 'KAYOS', 'GAYS', 'JOEYS', 'JESUS', 'BOYS',
          'EWING', 'ELLEN', 'ELLIE', 'ELLIS', 'HAYES', 'HESSE', 'INDIA', 'ITALY',
          'JONES', 'KENYA', 'MAINE', 'NEPAL', 'SAMOA', 'GHANA', 'SACHA', 'JANES',
          'EWERS', 'DIDOS', 'PAYNE', 'JULIA', 'JULIE', 'JONAH', 'JESTS', 'JEWS',
          'AKINS', 'BREDA', 'BREDS', 'CATHY', 'EDDIE', 'ELENA', 'ELMER', 'ERICA',
          'IRENE', 'JINNI', 'JATOS', 'PHILS', 'OZZIE', 'IOWAS', 'IXIAS', 'LEONA',
          'LEORS', 'LEVIS', 'MARYL', 'MARYS', 'MAORI', 'OASYS', 'IGUANA', 'CAFES',
          'GAOL', 'EBBED', 'DJINN', 'RIOJA', 'MARUS', 'JADED', 'JAINS', 'EATIN',
          'IXIA', 'OZARK'}
WORDS_5 = [w for w in WORDS_5 if w not in BANNED]
MUSIC = {w for w in MUSIC if len(w) == 5 and w.isalpha() and w not in BANNED}

# Pos-letter lookup
POS_MAP = defaultdict(set)
for w in WORDS_5:
  for i, ch in enumerate(w):
    POS_MAP[(i, ch)].add(w)

def all_words_for_pattern(p):
  # p is a 5-char string with letters or None
  result = None
  for i, ch in enumerate(p):
    if ch is None:
      continue
    s = POS_MAP[(i, ch)]
    result = s if result is None else (result & s)
    if not result:
      return set()
  return result if result is not None else set(WORDS_5)

def solve(rows, cols, used):
  """Pick the slot (row or col) with fewest candidates, branch on each."""
  if all(rows) and all(cols):
    return rows[:], cols[:]
  best = None
  best_options = None
  for i in range(5):
    if not rows[i]:
      pattern = [(cols[j][i] if cols[j] else None) for j in range(5)]
      opts = all_words_for_pattern(pattern) - used
      if best_options is None or len(opts) < len(best_options):
        best, best_options = ('R', i), opts
        if not opts:
          return None
  for i in range(5):
    if not cols[i]:
      pattern = [(rows[j][i] if rows[j] else None) for j in range(5)]
      opts = all_words_for_pattern(pattern) - used
      if best_options is None or len(opts) < len(best_options):
        best, best_options = ('C', i), opts
        if not opts:
          return None
  kind, idx = best
  # Sort candidates to prefer music words first
  sorted_opts = sorted(best_options, key=lambda w: (0 if w in MUSIC else 1, w))
  for w in sorted_opts:
    if kind == 'R':
      rows[idx] = w
    else:
      cols[idx] = w
    used.add(w)
    result = solve(rows, cols, used)
    if result:
      return result
    if kind == 'R':
      rows[idx] = None
    else:
      cols[idx] = None
    used.remove(w)
  return None

t0 = time.time()
# Try seeding row 0 with various music words for thematic variety
music5 = sorted(w for w in MUSIC if w in set(WORDS_5))
# Try the famous ones first
priority = ['ADELE', 'BOWIE', 'DRAKE', 'DYLAN', 'ELTON', 'ELVIS', 'EDDIE',
            'PIANO', 'BANJO', 'CELLO', 'BLUES', 'BEATS', 'CHORD', 'CHOIR',
            'LATIN', 'LAYLA', 'OPERA', 'TEMPO', 'TANGO', 'TENOR', 'LYRIC',
            'METAL', 'METRO', 'NOTES', 'PSALM', 'RADIO', 'SCALE', 'SCORE',
            'SONGS', 'STING', 'SWING', 'TUNES', 'VOCAL', 'VIOLA', 'HYMNS']
priority = [w for w in priority if w in set(WORDS_5)]
others = [w for w in music5 if w not in priority]
random.seed(20260513)
random.shuffle(others)
music5 = priority + others

solution = None
for seed in music5:
  rows = [None]*5; cols = [None]*5
  rows[0] = seed
  result = solve(rows, cols, {seed})
  if result:
    solution = result
    print(f'Seeded row 0 = {seed}')
    break
  if time.time() - t0 > 30:
    print('timeout')
    break

if not solution:
  print('NO SOLUTION')
  sys.exit(1)

rows, cols = solution
print(f'\nSolved in {time.time()-t0:.2f}s')
print('Grid:')
for r in range(5):
  print('  ' + ' '.join(rows[r]))

# Verify
for c in range(5):
  col_word = ''.join(rows[r][c] for r in range(5))
  if col_word != cols[c]:
    print(f'MISMATCH col {c}: {col_word} != {cols[c]}')
    sys.exit(1)
print('\nVerified ✓')
print(f'Across: {rows}')
print(f'Down:   {cols}')

# Output JSON for the front-end
out = {
  'size': 5,
  'across': rows,
  'down': cols,
}
import json
with open('puzzle.json', 'w') as f:
  json.dump(out, f, indent=2)
print('Wrote puzzle.json')
